// Kör funktionen när sidan laddas
window.onload = init;

function init() {
    processEmployeeData();
}

async function hämtaAnställda() {
    try {
        const response = await fetch('http://localhost:3000/employees');
        const data = await response.json();
        return data;
    } catch (error) {
        console.error('Fetch error:', error);
        throw error;
    }
}

async function processEmployeeData() {
    try {
        const result = await hämtaAnställda();
        console.log('Received data:', result);
        visaAnställda(result);
    } catch (error) {
        console.error('Error processing data:', error);
        const empList = document.getElementById('empList');
        if (empList) {
            empList.innerHTML = '<tr><td colspan="7" class="error">Kunde inte hämta data. Är servern igång?</td></tr>';
        }
    }
}

function visaAnställda(data) {
    const empList = document.getElementById('empList');
    
    empList.innerHTML = '';
    
    if (data.length === 0) {
        empList.innerHTML = '<tr><td colspan="7" style="text-align: center;">Inga anställda finns. Lägg till en!</td></tr>';
        return;
    }
    
    data.forEach((anställd) => {
        const rad = document.createElement('tr');
        
        const idCell = document.createElement('td');
        idCell.textContent = anställd.ID;
        rad.appendChild(idCell);
        
        const nameCell = document.createElement('td');
        nameCell.textContent = anställd.Name;
        rad.appendChild(nameCell);
        
        const lastnameCell = document.createElement('td');
        lastnameCell.textContent = anställd.Lastname;
        rad.appendChild(lastnameCell);
        
        const jobtitleCell = document.createElement('td');
        jobtitleCell.textContent = anställd.Jobtitle;
        rad.appendChild(jobtitleCell);
        
        const locationCell = document.createElement('td');
        locationCell.textContent = anställd.Location;
        rad.appendChild(locationCell);
        
        const dateCell = document.createElement('td');
        dateCell.textContent = anställd.Dateofbirth;
        rad.appendChild(dateCell);
        
        const actionCell = document.createElement('td');
        const deleteBtn = document.createElement('button');
        deleteBtn.textContent = '🗑️ Ta bort';
        deleteBtn.onclick = () => taBort(anställd.ID);
        actionCell.appendChild(deleteBtn);
        rad.appendChild(actionCell);
        
        empList.appendChild(rad);
    });
}

async function taBort(id) {
    if (!confirm('Är du säker på att du vill ta bort denna anställd?')) {
        return;
    }
    
    try {
        const response = await fetch(`http://localhost:3000/employees/${id}`, {
            method: 'DELETE'
        });
        
        if (response.ok) {
            document.getElementById('meddelande').innerHTML = '<p class="success">✅ Anställd borttagen!</p>';
            processEmployeeData();
        } else {
            document.getElementById('meddelande').innerHTML = '<p class="error">❌ Kunde inte ta bort</p>';
        }
    } catch (error) {
        console.error('Delete error:', error);
        document.getElementById('meddelande').innerHTML = '<p class="error">❌ Fel vid borttagning</p>';
    }
}

const form = document.getElementById('form');
if (form) {
    form.onsubmit = async (e) => {
        e.preventDefault();
        
        const Name = document.getElementById('Name').value.trim();
        const Lastname = document.getElementById('Lastname').value.trim();
        const Jobtitle = document.getElementById('Jobtitle').value.trim();
        const Location = document.getElementById('Location').value.trim();
        const Dateofbirth = document.getElementById('Dateofbirth').value;
        
        let fel = [];
        if (!Name) fel.push('Förnamn saknas');
        if (!Lastname) fel.push('Efternamn saknas');
        if (!Jobtitle) fel.push('Jobbtitel saknas');
        if (!Location) fel.push('Plats saknas');
        if (!Dateofbirth) fel.push('Födelsedatum saknas');
        
        if (fel.length > 0) {
            document.getElementById('meddelande').innerHTML = 
                `<div class="error">❌ ${fel.join('<br>')}</div>`;
            return;
        }
        
        const nyAnstalld = { Name, Lastname, Jobtitle, Location, Dateofbirth };
        
        try {
            const response = await fetch('http://localhost:3000/employees', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(nyAnstalld)
            });
            
            if (response.ok) {
                document.getElementById('meddelande').innerHTML = 
                    '<div class="success">✅ Sparad! Omdirigerar...</div>';
                setTimeout(() => {
                    window.location.href = 'index.html';
                }, 1000);
            } else {
                const felData = await response.json();
                if (felData.errors) {
                    document.getElementById('meddelande').innerHTML = 
                        `<div class="error">❌ ${felData.errors.join('<br>')}</div>`;
                } else {
                    document.getElementById('meddelande').innerHTML = 
                        '<div class="error">❌ Fel vid sparande</div>';
                }
            }
        } catch (error) {
            console.error('Post error:', error);
            document.getElementById('meddelande').innerHTML = 
                '<div class="error">❌ Kunde inte ansluta till servern</div>';
        }
    };
}